import type { Request, Response } from 'express';
import heicConvert from 'heic-convert';
import sharp from 'sharp';

import { contentTypeFromFormat, extFromFormat, replaceExt } from '../utils/content-type.js';
import { sendImageResponse } from '../utils/send-image.js';

const SHARP_FORMATS = ['jpg', 'jpeg', 'png', 'webp', 'avif', 'gif', 'tiff', 'jp2', 'heif', 'heic'] as const;

type SharpFormat = (typeof SHARP_FORMATS)[number];

export async function convertHandler(req: Request, res: Response): Promise<void> {
  try {
    if (!req.file) {
      res.status(400).json({ error: 'No file uploaded' });
      return;
    }

    const toFormat = String(req.body?.to ?? 'jpg').toLowerCase();
    const quality = Math.min(100, Math.max(1, parseInt(String(req.body?.quality ?? '90'), 10)));

    if (!SHARP_FORMATS.includes(toFormat as SharpFormat)) {
      res.status(400).json({
        error: `Output format must be one of: ${SHARP_FORMATS.join(', ')}`,
      });
      return;
    }

    const isHeic = /\.(heic|heif)$/i.test(req.file.originalname);

    let buffer: Buffer;

    if (isHeic) {
      const heicTarget: 'JPEG' | 'PNG' = toFormat === 'png' ? 'PNG' : 'JPEG';
      const opts: { buffer: Buffer; format: 'JPEG' | 'PNG'; quality?: number } = {
        buffer: req.file.buffer,
        format: heicTarget,
      };
      if (heicTarget === 'JPEG') {
        opts.quality = Math.max(0, Math.min(1, quality / 100));
      }
      const out = await heicConvert(opts);
      buffer = Buffer.from(out as ArrayBuffer);

      if (toFormat !== 'jpg' && toFormat !== 'jpeg' && toFormat !== 'png') {
        const sharpFormat = toFormat === 'jp2' ? 'jp2' : toFormat;
        const pipe = sharp(buffer);
        const transformed = await toSharpFormat(pipe, sharpFormat, quality);
        buffer = transformed;
      }
    } else {
      const pipe = sharp(req.file.buffer);
      const sharpFormat = toFormat === 'jp2' ? 'jp2' : toFormat;
      buffer = await toSharpFormat(pipe, sharpFormat, quality);
    }

    const ext = extFromFormat(toFormat);
    const contentType = contentTypeFromFormat(toFormat);
    const filename = replaceExt(req.file.originalname, ext);

    sendImageResponse(res, buffer, contentType, filename);
  } catch (err) {
    console.error('convert error:', err);
    res.status(500).json({
      error: err instanceof Error ? err.message : 'Conversion failed',
    });
  }
}

async function toSharpFormat(pipe: sharp.Sharp, format: string, quality: number): Promise<Buffer> {
  const qNum = Math.round(Math.min(100, Math.max(1, quality)));
  switch (format) {
    case 'jpeg':
    case 'jpg':
      return pipe.jpeg({ quality: qNum }).toBuffer();
    case 'png':
      return pipe.png().toBuffer();
    case 'webp':
      return pipe.webp({ quality: qNum }).toBuffer();
    case 'avif':
      return pipe.avif({ quality: qNum }).toBuffer();
    case 'gif':
      return pipe.gif().toBuffer();
    case 'tiff':
      return pipe.tiff({ quality: qNum }).toBuffer();
    case 'jp2':
      return pipe.jp2({ quality: qNum }).toBuffer();
    case 'heif':
    case 'heic':
      return pipe.heif({ quality: qNum }).toBuffer();
    default:
      return pipe.jpeg({ quality: qNum }).toBuffer();
  }
}
